<?phpinclude 'heador.php';include 'dbconnect.php';//open up databasemysql_select_db('HELPDISK');$cat = $_GET['cat'];$catnum = mysql_query ("SELECT catnum FROM categories WHERE category = '$cat'");$catno = mysql_fetch_row($catnum);//print ("Catno: ".$catno[0]."<br>\n");$catselect = mysql_query ("SELECT DISTINCT category FROM categories WHERE subcatof = '$catno[0]'");$count = mysql_num_rows($catselect);if ($count != 0) {	print ("<b>".$cat."</b> has ".$count." Subcategories:<br>\n");								while($row = mysql_fetch_array($catselect, MYSQL_BOTH))	{		print ("<a href=\"browseCat.php?cat=".$row["category"]."\"> ".$row["category"]."</a><br>\n");	}}print ("<DIV CLASS=\"str\"><p><br>URL's: <br></DIV>\n");$result = mysql_query ("SELECT * FROM url WHERE category = '$cat'");while($row = mysql_fetch_array($result, MYSQL_BOTH)){	print ("<a href=\"".$row["url"]."\" target=\"_blank\"> ".$row["name"]."</a><br>\n");}//close user connectionmysql_free_result($catselect);mysql_free_result($result);?></DIV></BODY></HTML>